mapper.select:
SELECT r.id, r.route_title_zh, r.pic_url
, fav.favorite_flg
FROM yy_route r JOIN ( SELECT route_id, COUNT(*) cnt FROM yy_order WHERE order_sts='03' AND order_type='04' AND create_time >= DATE_SUB(NOW(), INTERVAL #{days} DAY) GROUP BY route_id ORDER BY cnt DESC LIMIT #{topNums} ) t ON r.id = t.route_id
left outer join yy_user_favorite fav on r.id = fav.target_id and target_kbn = '03' and user_type = '01' and user_id = #{customerId}
ORDER BY t.cnt DESC;
